def main():
    scope  = ["https://spreadsheets.google.com/feeds","https://www.googleapis.com/auth/drive"]
    creds  = ServiceAccountCredentials.from_json_keyfile_name(CREDENTIALS_FILE, scope)
    client = gspread.authorize(creds)
    spread = client.open_by_key(SHEET_KEY)

    try:
        ws = spread.worksheet("القائمة_البيضاء")
        print(f"ورقة موجودة — {len(ws.get_all_values())} صف حالي")
    except gspread.WorksheetNotFound:
        ws = spread.add_worksheet(title="القائمة_البيضاء", rows=500, cols=10)
        print("تم إنشاء ورقة جديدة")

    ws.clear()
    ws.update("A1", EMPLOYEES)
    print(f"✅ تم رفع {len(EMPLOYEES)-1} موظفة بنجاح!")

if __name__ == "__main__":
    main()